import React from "react"

interface HeroInterface {
  title: string
  subtitle: string
}

/**
 * Hero used on the home page and other landing pages
 * @param props <HeroInterface> provides the title and subtitle for the Hero component
 */
const Hero: React.FunctionComponent<HeroInterface> = props => {
  return (
    <div className="py-40 bg-black">
      <div className="container mx-auto px-6">
        <h2 className="text-4xl font-bold mb-2 text-white">{props.title}</h2>
        <h3 className="text-2xl mb-8 text-gray-200">{props.subtitle}</h3>
      </div>
      {props.children}
    </div>
  )
}

export default Hero
